import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import FlashBar from '../components/FlashBar';

function MainLayout({ children }) {
  const { role, flash, logout } = useAuth();
  const location = useLocation();

  const links = [
    { to: '/dashboard', label: 'Dashboard' },
    { to: '/verify', label: 'Verify Contacts' },
    { to: '/notifications', label: 'Notifications' },
  ];

  if (role === 'DONOR') {
    links.push({ to: '/donor', label: 'Donor Center' });
  }
  if (role === 'RECIPIENT') {
    links.push({ to: '/recipient', label: 'Recipient Center' });
  }
  if (role === 'ADMIN') {
    links.push({ to: '/admin', label: 'Admin Console' });
  }

  return (
    <div className="app-shell">
      <header className="hero">
        <div className="hero-inner">
          <h1>Blood and Organ Donation Portal</h1>
          <p className="subtitle">Operational dashboard for real donor-recipient workflows.</p>
          <div className="status-row">
            <span className="chip">Role: {role || 'Guest'}</span>
            <a href="http://localhost:8002/docs" target="_blank" rel="noreferrer">Open API Docs</a>
          </div>
        </div>
      </header>

      <main className="layout app-grid">
        <aside className="panel sidebar">
          <h3>Navigation</h3>
          <nav className="nav-list">
            {links.map((item) => (
              <Link
                key={item.to}
                to={item.to}
                className={location.pathname === item.to ? 'nav-link active' : 'nav-link'}
              >
                {item.label}
              </Link>
            ))}
          </nav>
          <button className="danger" onClick={logout}>Logout</button>
        </aside>

        <section className="content-area">
          <div className="panel full">
            <FlashBar flash={flash} />
          </div>
          {children}
        </section>
      </main>
    </div>
  );
}

export default MainLayout;
